ate\r\nfunction onSave()\r\n    if set then\r\n        local state = { set = set }\r\n        return JSON.encode(state)\r\n    end\r\nend\r\n\r\n-- Restore self state\r\nfunction onLoad(save_state)\r\n    if save_state ~= \u0027\u0027 and save_state ~= \u0027null\u0027 and save_state ~= nil then\r\n        set = JSON.decode(save_state).set\r\n        self.UI.hide(\u0022Move\u0022)\r\n    end\r\nend\r\n\r\n-- Set function for external calls\r\nfunction manualSet(arg)\r\n    ship = arg.ref\r\n    set = true\r\n    self.setRotationSmooth(ship.getRotation())\r\nend\r\n\r\n-- Set name on drop near a ship\r\nfunction onDropped()\r\n    local nearest = Global.call(\u0022API_FindNearestShip\u0022, { object = self, max_distance = 100 })\r\n    if nearest ~= nil then\r\n        ship = nearest\r\n        set = true\r\n        self.setRotation(nearest.getRotation())\r\n\r\n        printToAll(ship.getName() .. \u0022 takes an ion token\u0022)\r\n    else\r\n        ship = nil\r\n        set = false\r\n    end\r\nend\r\n\r\nstat = false\r\n\r\nfunction onContextOpen(player_color)\r\n    if set then\r\n        showBtn()\r\n    end\r\nend\r\n\r\nfunction showBtn()\r\n    if stat == false and ship ~= nil then\r\n        if self.is_face_down then\r\n            self.UI.setAttribute(\u0022Center\u0022, \u0022rotation\u0022, \u0022180 0 0\u0022)\r\n            self.UI.setAttribute(\u0022Center\u0022, \u0022position\u0022, \u00220 0 30\u0022)\r\n        else\r\n            self.UI.setAttribute(\u0022Center\u0022, \u0022rotation\u0022, \u00220 0 180\u0022)\r\n            self.UI.setAttribute(\u0022Center\u0022, \u0022position\u0022, \u00220 0 -30\u0022)\r\n        end\r\n        self.UI.show(\u0022Center\u0022)\r\n        stat = true\r\n    end\r\nend\r\n\r\nfunction hideBtn()\r\n    if stat == true then\r\n        self.UI.hide(\u0022Center\u0022)\r\n        stat = false\r\n    end\r\nend\r\n\r\nfunction ionMove()\r\n    ship.setDescription(\u0027s1\u0027)\r\nend\r\n\r\nfunction ionMoveL()\r\n    ship.setDescription(\u0027bl1\u0027)\r\nend\r\n\r\nfunction ionMoveR()\r\n    ship.setDescription(\u0027br1\u0027)\r\nend\r\n\r\nfunction Delete()\r\n    self.destruct()\r\nend\r\n\nend)\n__bundle_register(\u0022Dim\u0022, function(require, _LOADED, __bundle_register, __bundle_modules)\n-- ~~~~~~\r\n-- Script by dzikakulka\r\n-- Issues, history at: http://github.com/tjakubo2/TTS_xwing\r\n--\r\n-- X-Wing related measurements for TTS\r\n-- ~~~~~~\r\n\r\nlocal Dim = {}\r\n\r\n-- adjusted length = 40mm = 1.4536igu\r\n-- 1mm = 0.03612igu\r\nDim.mm_igu_ratio = 0.03637\r\n\r\n-- 40mm = 1.445igu\r\n-- (s1 length / small base size)\r\n\r\n-- 1mm = 0.036125igu\r\n-- mm_igu_ratio = 0.036125\r\n\r\n-- Millimeter dimensions of ship bases\r\nDim.mm_baseSize = {\r\n    small = 40,\r\n    medium = 60,\r\n    large = 80,\r\n    huge = 80,\r\n    smallBase = 40,\r\n    mediumBase = 60,\r\n    largeBase = 80,\r\n    hugeBase = 80,\r\n    objective = 36,\r\n}\r\n\r\nDim.mm_smallBase = Dim.mm_baseSize.small\r\nDim.mm_mediumBase = Dim.mm_baseSize.medium\r\nDim.mm_largeBase = Dim.mm_baseSize.large\r\n\r\n----------------------------------------\r\n-- Standard X-Wing Maneuver Templates --\r\n----------------------------------------\r\n\r\nDim.XWingTemplates = {\r\n    straight = { 40, 80, 120, 160, 200 }, -- Speed to millimeters\r\n    turn = { 35, 62.5, 90 },              -- Turn Middle Radius (mm)\r\n    bank = { 80, 130, 180 },              -- Bank Middle Radius (mm)\r\n}\r\n\r\n-- Millimeter dimensions for cards\r\nDim.mm_upgrade_width = 41\r\nDim.mm_upgrade_height = 63\r\nDim.mm_pilot_width = 63.5\r\nDim.mm_pilot_height = 88\r\n\r\nDim.mm_ship_scale = vector(0.629, 0.629, 0.629)\r\n\r\nDim.mm_cardSize = {\r\n    upgrade = { width = 41, height = 63 },\r\n    pilot = { width = 63.5, height = 88 }\r\n}\r\n\r\n-- Millimeter dimension for dial cards\r\nDim.mm_dialSize = 54\r\n\r\n-- Convert argument from MILLIMETERS to IN-GAME UNITS\r\nfunction Dim.Convert_mm_igu(millimeters)\r\n    return millimeters * Dim.mm_igu_ratio\r\nend\r\n\r\n-- Convert argument from IN-GAME UNITS to MILLIMETERS\r\nfunction Dim.Convert_igu_mm(in_game_units)\r\n    return in_game_units / Dim.mm_igu_ratio\r\nend\r\n\r\nreturn Dim\r\n\nend)\nreturn __bundle_require(\u0022Ion.2e6667.lua\u0022)